INSERT INTO public.result (id, quiz_id, title_text, description, cta_text, cta_url, range_lo, range_hi, created_at, updated_at) VALUES ('09fe6763-e59d-4f33-94ba-a9e65f2fc53a', '1b52f940-a5b7-471c-8a4d-78d12f27cf56', 'You''re Already Eating Pretty Clean 🥦', 'Your habits show real awareness — you cook at home, read labels, and keep processed foods to a minimum. Olive can help you keep that momentum and discover even better options.', 'See How Olive Can Help', 'https://oliveapp.com/', 0, 20, '2026-04-28 19:23:51.914788+00', '2026-04-28 19:23:51.914788+00');
INSERT INTO public.result (id, quiz_id, title_text, description, cta_text, cta_url, range_lo, range_hi, created_at, updated_at) VALUES ('509e39e0-713e-4997-9d24-c65acefa3cc1', '1b52f940-a5b7-471c-8a4d-78d12f27cf56', 'You''re Doing Okay, But There''s Room to Improve 🤔', 'You''re making some good choices, but ultra-processed foods are sneaking in more than you might realize. Olive can help you spot them and swap them out without overhauling your whole routine.', 'Try Olive Free', 'https://oliveapp.com/', 21, 45, '2026-04-28 19:23:51.914788+00', '2026-04-28 19:23:51.914788+00');
INSERT INTO public.result (id, quiz_id, title_text, description, cta_text, cta_url, range_lo, range_hi, created_at, updated_at) VALUES ('247720b5-b4e1-4cff-87e9-684b368cf9e7', '1b52f940-a5b7-471c-8a4d-78d12f27cf56', 'Ultra-Processed Foods Are a Regular Part of Your Diet ⚠️', 'Your diet leans heavily on convenience and packaged foods — which is super common, but worth addressing. Olive was built for exactly this: making it easier to eat better without the overwhelm.', 'Give Olive a Try', 'https://oliveapp.com/#features', 46, 70, '2026-04-28 19:23:51.914788+00', '2026-04-28 19:23:51.914788+00');
INSERT INTO public.result (id, quiz_id, title_text, description, cta_text, cta_url, range_lo, range_hi, created_at, updated_at) VALUES ('7db0117c-29ea-4185-b015-3df9241f8323', '1b52f940-a5b7-471c-8a4d-78d12f27cf56', 'Time for a Real Reset 🚨', 'Your eating habits are heavily driven by ultra-processed foods, and it''s likely affecting how you feel. Olive can be your guide to understanding what''s actually in your food and making changes that stick.', 'Start Your Reset with Olive', 'https://oliveapp.com/#features', 71, 100, '2026-04-28 19:23:51.914788+00', '2026-04-28 19:23:51.914788+00');
INSERT INTO public.result (id, quiz_id, title_text, description, cta_text, cta_url, range_lo, range_hi, created_at, updated_at) VALUES ('2f40944b-2ed8-4e4b-a41e-963efd8db859', 'db563400-9f75-4ca6-b6ae-d1c7d7d56a6f', 'The Label Detective', 'You don''t eat a meal — you investigate one. You''ve read more ingredient lists than most people have read novels, and you''re proud of it. Your superpower: knowing exactly what''s in everything. Your kryptonite: the 45-minute grocery run.', 'See how Olive helps you decode labels instantly', 'https://oliveapp.com/', 13, 19, '2026-04-28 19:24:47.876037+00', '2026-04-28 19:24:47.876037+00');
INSERT INTO public.result (id, quiz_id, title_text, description, cta_text, cta_url, range_lo, range_hi, created_at, updated_at) VALUES ('29fabdfd-63c4-4142-ac26-e2bb69890bd1', 'db563400-9f75-4ca6-b6ae-d1c7d7d56a6f', 'The Conscious Muncher', 'You care about what you eat but you''re not obsessive about it. You''ll read the label if it''s right there, and you''ve definitely Googled ''is oat milk actually healthy'' at least once. Balance is your brand.', 'Explore Olive''s food tracking features', 'https://oliveapp.com/#features', 8, 12, '2026-04-28 19:24:47.876037+00', '2026-04-28 19:24:47.876037+00');
INSERT INTO public.result (id, quiz_id, title_text, description, cta_text, cta_url, range_lo, range_hi, created_at, updated_at) VALUES ('e92e9e10-68cc-438c-a949-8f7c522e2f6c', 'db563400-9f75-4ca6-b6ae-d1c7d7d56a6f', 'The Adventurous Omnivore', 'You''ll try anything once — twice if it''s spicy. Nutrition labels feel like a buzzkill and life''s too short not to eat the mystery dip. You bring maximum energy to every meal and zero spreadsheets.', 'Discover new foods with Olive', 'https://oliveapp.com/', 4, 7, '2026-04-28 19:24:47.876037+00', '2026-04-28 19:24:47.876037+00');
INSERT INTO public.result (id, quiz_id, title_text, description, cta_text, cta_url, range_lo, range_hi, created_at, updated_at) VALUES ('8bf44963-049e-4029-b5f9-4a34e2796779', 'db563400-9f75-4ca6-b6ae-d1c7d7d56a6f', 'The Blissfully Unaware', 'Food is fuel and also joy and honestly you don''t overthink it. You''ve eaten cereal for dinner and felt great about it. You live in the moment, one mystery snack at a time. No notes. No regrets.', 'Let Olive do the thinking for you', 'https://oliveapp.com/', 0, 3, '2026-04-28 19:24:47.876037+00', '2026-04-28 19:24:47.876037+00');
